-- 1. Detach the 3 mis-tagged "specials" blocks (they were morning_warmup test rows, not specials).
UPDATE scheduleBlocks SET subjectId = NULL WHERE subjectId = 60002;

-- 2. Rename ELA to canonical "Reading and Language Arts (ELA)".
UPDATE subjects SET name = 'Reading and Language Arts (ELA)' WHERE slug = 'ela';

-- 3. Add the two missing canonical subjects.
INSERT INTO subjects (slug, name, color, emoji, sortOrder)
VALUES ('health-pe', 'Health and PE', '#22c55e', '🏃', 5)
ON DUPLICATE KEY UPDATE name=VALUES(name), color=VALUES(color), emoji=VALUES(emoji), sortOrder=VALUES(sortOrder);

INSERT INTO subjects (slug, name, color, emoji, sortOrder)
VALUES ('art-music', 'Art and Music', '#14b8a6', '🎨', 6)
ON DUPLICATE KEY UPDATE name=VALUES(name), color=VALUES(color), emoji=VALUES(emoji), sortOrder=VALUES(sortOrder);

-- 4. Reorder the existing rows to match Mom's canonical list
--    (Social Studies, Science, ELA, Math, Health and PE, Art and Music, Other).
UPDATE subjects SET sortOrder = 1 WHERE slug = 'social';
UPDATE subjects SET sortOrder = 2 WHERE slug = 'science';
UPDATE subjects SET sortOrder = 3 WHERE slug = 'ela';
UPDATE subjects SET sortOrder = 4 WHERE slug = 'math';
UPDATE subjects SET sortOrder = 5 WHERE slug = 'health-pe';
UPDATE subjects SET sortOrder = 6 WHERE slug = 'art-music';
UPDATE subjects SET sortOrder = 7 WHERE slug = 'other';

-- 5. Retire 'specials' by renaming the slug + name (keeps row-level FK history but hides it from pickers).
UPDATE subjects SET slug = '_deprecated_specials', name = '(deprecated) Specials', sortOrder = 999 WHERE slug = 'specials';

-- Verify final state.
SELECT id, slug, name, color, emoji, sortOrder FROM subjects ORDER BY sortOrder, id;

